window.deckData={deckByRank:{2:[{suit:"♦",val:"2",category:"ancestor",main:"descended from Abraham",ref:"Gen 12:3 / 22:18",text:"I will bless those who bless you… all peoples blessed."},{suit:"♣",val:"2",category:"ancestor",main:"descended from Isaac",ref:"Gen 17:19 / 21:12",text:"Sarah will bear you a son, Isaac… covenant."},{suit:"♠",val:"2",category:"ancestor",main:"descended from Jacob",ref:"Num 24:17",text:"A star will come out of Jacob; a scepter out of Israel."},{suit:"♥",val:"2",category:"ancestor",main:"descended from Judah / King",ref:"Gen 49:10",text:"The scepter not depart from Judah until Shiloh comes."}],3:[{suit:"♦",val:"3",category:"ancestor",main:"heir to David's throne",ref:"2Sam 7:12-13 / Isa 9:7",text:"I will establish his kingdom forever."},{suit:"♣",val:"3",category:"mother",main:"born of a virgin · Immanuel",ref:"Isa 7:14",text:"The virgin will be with child… Immanuel."},{suit:"♠",val:"3",category:"birthplace",main:"born in Bethlehem",ref:"Mic 5:2",text:"Bethlehem Ephrathah, out of you will come forth a ruler."},{suit:"♥",val:"3",category:"early years",main:"spent time in Egypt",ref:"Hos 11:1",text:"Out of Egypt I called My son."}],4:[{suit:"♦",val:"4",category:"home town",main:"called a Nazarene",ref:"Isa 11:1",text:"A shoot from the stump of Jesse."},{suit:"♣",val:"4",category:"spiritual vanguard",main:"messenger prepares the way",ref:"Isa 40:3-5",text:"A voice calling: 'Prepare the way for the LORD.'"},{suit:"♠",val:"4",category:"to be heralded",main:"Elijah-style prophet",ref:"Mal 4:5-6",text:"I will send you Elijah the prophet."},{suit:"♥",val:"4",category:"mission",main:"prophet like Moses",ref:"Deut 18:15",text:"The LORD will raise up a prophet like me."}],5:[{suit:"♦",val:"5",category:"mission",main:"light to Galilee",ref:"Isa 9:1-2",text:"People walking in darkness have seen a great light."},{suit:"♣",val:"5",category:"mission",main:"heal brokenhearted",ref:"Isa 61:1-2",text:"Bind up the brokenhearted, proclaim liberty."},{suit:"♠",val:"5",category:"mission",main:"priest Melchizedek",ref:"Ps 110:4",text:"You are a priest forever in the order of Melchizedek."},{suit:"♥",val:"5",category:"mission",main:"temple cleaner",ref:"Ps 69:9",text:"Zeal for Your house has consumed me."}],6:[{suit:"♦",val:"6",category:"communicator",main:"speak in parables",ref:"Ps 78:2-4",text:"I will open my mouth in parables."},{suit:"♣",val:"6",category:"role",main:"declared Son of God",ref:"Ps 2:7",text:"You are My Son; today I have become Your Father."},{suit:"♠",val:"6",category:"role",main:"humble king on donkey",ref:"Zech 9:9",text:"Your King comes… riding on a donkey."},{suit:"♥",val:"6",category:"role",main:"eternal King",ref:"Dan 2:44",text:"God of heaven will set up a kingdom never destroyed."}],7:[{suit:"♦",val:"7",category:"role",main:"King over nations",ref:"Num 24:17",text:"A star out of Jacob, a scepter out of Israel."},{suit:"♣",val:"7",category:"who accepted him",main:"children praised him",ref:"Ps 8:2",text:"From mouths of children You ordered praise."},{suit:"♠",val:"7",category:"betrayal",main:"hated without cause",ref:"Ps 35:19 / 69:4",text:"Those who hate me without cause outnumber my hairs."},{suit:"♥",val:"7",category:"rejection",main:"rejected by his own",ref:"Ps 69:8 / Isa 53:3",text:"Stranger to my brothers… despised and rejected."}],8:[{suit:"♦",val:"8",category:"betrayal",main:"betrayed by a friend",ref:"Ps 41:9 / Zech 11:12-13",text:"My close friend lifted heel against me. Thirty silver."},{suit:"♣",val:"8",category:"betrayal",main:"30 silver → potter's field",ref:"Zech 11:12-13",text:"Thirty pieces of silver… throw to potter."},{suit:"♠",val:"8",category:"betrayal",main:"falsely accused",ref:"Ps 35:11",text:"Malicious witnesses rise up."},{suit:"♥",val:"8",category:"trial",main:"silent before accusers",ref:"Isa 53:7",text:"He did not open His mouth."}],9:[{suit:"♦",val:"9",category:"crucifixion",main:"spat upon, struck, beard torn",ref:"Isa 50:6",text:"I offered My back to those who struck Me."},{suit:"♣",val:"9",category:"crucifixion",main:"mocked and ridiculed",ref:"Ps 22:7-8",text:"All who see me mock me; they sneer."},{suit:"♠",val:"9",category:"crucifixion",main:"hands & feet pierced",ref:"Ps 22:16 / Zech 12:10",text:"They have pierced my hands and my feet."},{suit:"♥",val:"9",category:"crucifixion",main:"gamble for clothes",ref:"Ps 22:18",text:"They divide my garments and cast lots."}],10:[{suit:"♦",val:"10",category:"crucifixion",main:"vinegar to drink",ref:"Ps 69:21",text:"They gave me vinegar for my thirst."},{suit:"♣",val:"10",category:"crucifixion",main:"forsaken by God",ref:"Ps 22:1",text:"My God, my God, why have You forsaken me?"},{suit:"♠",val:"10",category:"crucifixion",main:"no bone broken",ref:"Ex 12:46 / Ps 34:20",text:"Not one of His bones will be broken."},{suit:"♥",val:"10",category:"forgiveness",main:"prayed for enemies",ref:"Ps 109:4",text:"I am a man of prayer."}],J:[{suit:"♦",val:"J",category:"crucifixion",main:"pierced for transgressions",ref:"Isa 53:5",text:"He was pierced for our transgressions."},{suit:"♣",val:"J",category:"crucifixion",main:"pierced side",ref:"Zech 12:10 / Ps 22:16",text:"They will look on Me, the One they have pierced."},{suit:"♠",val:"J",category:"burial",main:"buried with the rich",ref:"Isa 53:9",text:"With a rich man in His death."},{suit:"♥",val:"J",category:"resurrection",main:"rise from the dead",ref:"John 2:19",text:"Destroy this temple, in three days I will raise it."}],Q:[{suit:"♦",val:"Q",category:"resurrection",main:"third day He will raise us",ref:"Hos 6:2",text:"On the third day He will raise us up."},{suit:"♣",val:"Q",category:"resurrection",main:"not see decay",ref:"Ps 16:10 / Isa 53:10-11",text:"You will not abandon my soul to Sheol."},{suit:"♠",val:"Q",category:"resurrection",main:"seated at God's right hand",ref:"Ps 68:18 / 110:1",text:"Sit at My right hand."},{suit:"♥",val:"Q",category:"mission success",main:"bore sin of many",ref:"Isa 53:12",text:"He bore the sin of many."}],K:[{suit:"♦",val:"K",category:"independent reporter",main:"Tacitus · Christus",ref:"Annals AD 115-120",text:"Roman historian mentions 'Christus' and Christians."},{suit:"♣",val:"K",category:"independent reporter",main:"Josephus · Antiquities",ref:"Antiquities AD 93-94",text:"Flavius Josephus includes two references to Jesus."},{suit:"♠",val:"K",category:"independent reporter",main:"Pliny to Trajan",ref:"Letter AD 112",text:"Pliny the Younger wrote to Trajan about Christians."},{suit:"♥",val:"K",category:"affiliated reporter",main:"Epistles & Gospels",ref:"AD 48–110",text:"Paul, James, eyewitnesses — over 64,000 words."}],A:[{suit:"♦",val:"A",category:"rock evidence",main:"Pilate Stone",ref:"AD 26-36",text:"Limestone inscription confirms Pontius Pilate."},{suit:"♣",val:"A",category:"rock evidence",main:"Ossuary of Caiaphas",ref:"AD 20-60",text:"'Joseph, son of Caiaphas' — high priest."},{suit:"♠",val:"A",category:"rock evidence",main:"Synagogue at Capernaum",ref:"1st cent. basalt",text:"First-century synagogue where Jesus taught."},{suit:"♥",val:"A",category:"rock evidence",main:"Pool of Siloam",ref:"Hezekiah / Herodian",text:"Discovered 2004; steps where Jesus healed blind man."}]},jokerCards:[{suit:"🃏",val:"JOKER",category:"Screwtape",main:"Letter to Nightshade",ref:"classified",text:"My dear Nightshade … refute them all! Wormwood got eaten. Walked straight into the trap."},{suit:"🃏",val:"JOKER",category:"MI7 TOP SECRET",main:"Declassified",ref:"NIGHTSHADE",text:"QR leads to declassified file. Walked straight into the trap."}],allPropheciesData:[{prophecy:"Genesis 3:15",description:"Seed of a woman (virgin birth)",otText:"And I will put enmity between you and the woman, and between your seed and her seed. He will crush your head, and you will strike His heel.”",fulfillment1:"Galatians 4:4–5",fulfillment1Text:"4 But when the time had fully come, God sent His Son, born of a woman, born under the law, 5 to redeem those under the law, that we might receive our adoption as sons.",fulfillment2:"Matthew 1:18",fulfillment2Text:"This is how the birth of Jesus Christ came about: His mother Mary was pledged to be married to Joseph, but before they came together, she was found to be pregnant through the Holy Spirit."},{prophecy:"Genesis 3:15",description:"He will bruise Satan’s head",otText:"And I will put enmity between you and the woman, and between your seed and her seed. He will crush your head, and you will strike His heel.”",fulfillment1:"Hebrews 2:14",fulfillment1Text:"Therefore, since the children have flesh and blood, He too shared in their humanity, so that by His death He might destroy him who holds the power of death, that is, the devil,",fulfillment2:"1 John 3:8",fulfillment2Text:"The one who practices sin is of the devil, because the devil has been sinning from the beginning. This is why the Son of God was revealed: to destroy the works of the devil."},{prophecy:"Genesis 5:24",description:"The bodily ascension to heaven illustrated",otText:"Enoch walked with God; then he was no more, because God had taken him away.",fulfillment1:"Mark 16:19",fulfillment1Text:"After the Lord Jesus had spoken to them, He was taken up into heaven and sat at the right hand of God.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Genesis 9:26–27",description:"The God of Shem will be the Son of Shem",otText:"26 He also said, “Blessed be the LORD, the God of Shem! May Canaan be the servant of Shem. 27 May God extend the territory of Japheth; may he dwell in the tents of Shem, and may Canaan be his servant.”",fulfillment1:"Luke 3:36",fulfillment1Text:"the son of Cainan, the son of Arphaxad, the son of Shem, the son of Noah, the son of Lamech,",fulfillment2:"",fulfillment2Text:""},{prophecy:"Genesis 12:3",description:"Seed of Abraham will bless all nations",otText:"I will bless those who bless you, and whoever curses you I will curse; and all peoples on earth will be blessed through you.”",fulfillment1:"Galatians 3:8",fulfillment1Text:"The Scripture foresaw that God would justify the Gentiles by faith, and foretold the gospel to Abraham: “All nations will be blessed through you.”",fulfillment2:"Acts 3:25–26",fulfillment2Text:"25 And you are heirs of the prophets and of the covenant God made with your fathers when He said to Abraham, ‘Through your offspring all the families of the earth will be blessed.’ 26 When God raised up His servant, He sent Him first to you to bless you by turning each of you from your wicked ways.”"},{prophecy:"Genesis 12:7",description:"The Promise made to Abraham’s Seed",otText:"The LORD appeared to Abram and said, “To your offspring I will give this land.” So he built an altar there to the LORD, who had appeared to him.",fulfillment1:"Galatians 3:16",fulfillment1Text:"The promises were spoken to Abraham and to his seed. The Scripture does not say, “and to seeds,” meaning many, but “and to your seed,” meaning one, who is Christ.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Genesis 14:18",description:"A priest after the order of Melchizedek",otText:"Then Melchizedek king of Salem brought out bread and wine—he was the priest of God Most High—",fulfillment1:"Hebrews 6:20",fulfillment1Text:"where Jesus, our forerunner, has entered on our behalf. He has become a high priest forever, in the order of Melchizedek.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Genesis 14:18",description:"King of Peace and Righteousness",otText:"Then Melchizedek king of Salem brought out bread and wine—he was the priest of God Most High—",fulfillment1:"Hebrews 7:2",fulfillment1Text:"and Abraham gave him a tenth of everything. First, his name means “king of righteousness”; then also, “king of Salem” means “king of peace.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Genesis 14:18",description:"The Last Supper foreshadowed",otText:"Then Melchizedek king of Salem brought out bread and wine—he was the priest of God Most High—",fulfillment1:"Matthew 26:26–29",fulfillment1Text:"26 While they were eating, Jesus took bread, spoke a blessing and broke it, and gave it to His disciples, saying, “Take and eat; this is My body.” 27 Then He took a cup, gave thanks, and gave it to them, saying, “Drink from it, all of you. 28 This is My blood of the covenant, which is poured out for many for the forgiveness of sins. 29 I tell you, I will not drink of this fruit of the vine from now on until that day when I drink it anew with you in My Father’s kingdom.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Genesis 17:19",description:"Seed of Isaac (Gen 21:12)",otText:"But God replied, “Your wife Sarah will indeed bear you a son, and you will name him Isaac. I will establish My covenant with him as an everlasting covenant for his descendants after him.",fulfillment1:"Romans 9:7",fulfillment1Text:"Nor because they are Abraham’s descendants are they all his children. On the contrary, “Through Isaac your offspring will be reckoned.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Genesis 22:8",description:"The Lamb of God promised",otText:"Abraham answered, “God Himself will provide the lamb for the burnt offering, my son.” And the two of them walked on together.",fulfillment1:"John 1:29",fulfillment1Text:"The next day John saw Jesus coming toward him and said, “Look, the Lamb of God, who takes away the sin of the world!”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Genesis 22:18",description:"As Isaac’s seed, will bless all nations",otText:"And through your offspring all nations of the earth will be blessed, because you have obeyed My voice.”",fulfillment1:"Galatians 3:16",fulfillment1Text:"The promises were spoken to Abraham and to his seed. The Scripture does not say, “and to seeds,” meaning many, but “and to your seed,” meaning one, who is Christ.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Genesis 26:2–5",description:"The Seed of Isaac promised as the Redeemer",otText:"2 The LORD appeared to Isaac and said, “Do not go down to Egypt; live in the land where I tell you to stay. 3 Stay in this land as a foreigner, and I will be with you and bless you... 4 I will make your descendants as numerous as the stars... 5 because Abraham listened to My voice and kept My charge, My commandments, My statutes, and My laws.”",fulfillment1:"Hebrews 11:18",fulfillment1Text:"even though God had said to him, “Through Isaac your offspring will be reckoned.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Genesis 28:12",description:"The Bridge to heaven",otText:"And he had a dream in which he saw a stairway resting on the earth, with its top reaching to heaven, and the angels of God were ascending and descending on it.",fulfillment1:"John 1:51",fulfillment1Text:"Then He declared, “Truly, truly, I tell you, you will see heaven open and the angels of God ascending and descending on the Son of Man.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Genesis 28:14",description:"The Seed of Jacob",otText:"Your descendants will be like the dust of the earth, and you will spread out to the west and east and north and south. All the peoples on earth will be blessed through you and your offspring.”",fulfillment1:"Luke 3:34",fulfillment1Text:"the son of Jacob, the son of Isaac, the son of Abraham, the son of Terah, the son of Nahor,",fulfillment2:"",fulfillment2Text:""},{prophecy:"Genesis 49:10",description:"The time of His coming",otText:"The scepter will not depart from Judah, nor the staff from between his feet, until Shiloh comes and the allegiance of the nations is his.",fulfillment1:"Luke 2:1–7",fulfillment1Text:"1 In those days a decree went out from Caesar Augustus that a census should be taken of the entire Roman world. 2 This was the first census to take place while Quirinius was governor of Syria. 3 And everyone went to his own town to register. 4 So Joseph also went up from the town of Nazareth in Galilee to Judea, to Bethlehem the city of David, because he was of the house and line of David. 5 He went there to register with Mary, who was pledged to be married to him and was expecting a child. 6 While they were there, the time came for her to give birth, 7 and she gave birth to her firstborn, a son. She wrapped Him in swaddling clothes and laid Him in a manger, because there was no room for them in the inn.",fulfillment2:"Galatians 4:4",fulfillment2Text:"But when the time had fully come, God sent His Son, born of a woman, born under the law,"},{prophecy:"Genesis 49:10",description:"The Seed of Judah",otText:"The scepter will not depart from Judah, nor the staff from between his feet, until Shiloh comes and the allegiance of the nations is his.",fulfillment1:"Luke 3:33",fulfillment1Text:"the son of Amminadab, the son of Admin, the son of Arni, the son of Hezron, the son of Perez, the son of Judah,",fulfillment2:"",fulfillment2Text:""},{prophecy:"Genesis 49:10",description:"Called Shiloh or One Sent",otText:"The scepter will not depart from Judah, nor the staff from between his feet, until Shiloh comes and the allegiance of the nations is his.",fulfillment1:"John 17:3",fulfillment1Text:"Now this is eternal life: that they may know You, the only true God, and Jesus Christ, whom You have sent.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Genesis 49:10",description:"Messiah to come before Judah lost identity",otText:"The scepter will not depart from Judah, nor the staff from between his feet, until Shiloh comes and the allegiance of the nations is his.",fulfillment1:"John 11:47–52",fulfillment1Text:"47 Then the chief priests and Pharisees called a meeting of the Sanhedrin. “What are we doing?” they asked. “This man is performing many signs. 48 If we let Him go on like this, everyone will believe in Him, and then the Romans will come and take away both our place and our nation.” 49 But one of them, named Caiaphas, who was high priest that year, said to them, “You know nothing at all! 50 You do not realize that it is better for you that one man die for the people than that the whole nation perish.” 51 He did not say this on his own, but as high priest that year he prophesied that Jesus would die for the nation, 52 and not only for the nation, but also for the scattered children of God, to gather them together into one.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Genesis 49:10",description:"Unto Him shall the obedience of the people be",otText:"The scepter will not depart from Judah, nor the staff from between his feet, until Shiloh comes and the allegiance of the nations is his.",fulfillment1:"John 10:16",fulfillment1Text:"I have other sheep that are not of this fold. I must bring them also, and they will listen to My voice. Then there will be one flock and one shepherd.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Exodus 3:13–15",description:"The Great “I AM”",otText:"13 Then Moses said to God, “Suppose I go to the Israelites... what shall I tell them?” 14 God said to Moses, “I AM WHO I AM. This is what you are to say to the Israelites: ‘I AM has sent me to you.’” 15 God also said to Moses... “This is My name forever, and this is how I am to be remembered from generation to generation.”",fulfillment1:"John 4:26",fulfillment1Text:"“I who speak to you am He,” Jesus declared.",fulfillment2:"John 8:58",fulfillment2Text:"“Truly, truly, I tell you,” Jesus declared, “before Abraham was born, I am!”"},{prophecy:"Exodus 12:5",description:"A Lamb without blemish",otText:"Your lamb must be a year-old male without blemish; you may take it from the sheep or the goats.",fulfillment1:"Hebrews 9:14",fulfillment1Text:"how much more will the blood of Christ, who through the eternal Spirit offered Himself unblemished to God, purify our consciences from works of death, so that we may serve the living God!",fulfillment2:"1 Peter 1:19",fulfillment2Text:"but with the precious blood of Christ, a lamb without blemish or defect."},{prophecy:"Exodus 12:13",description:"The blood of the Lamb saves from wrath",otText:"The blood will be a sign for you on the houses where you are. When I see the blood, I will pass over you. No destructive plague will touch you when I strike the land of Egypt.",fulfillment1:"Romans 5:8",fulfillment1Text:"But God proves His love for us in this: While we were still sinners, Christ died for us.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Exodus 12:21–27",description:"Christ is our Passover",otText:"(The account of Moses summoning the elders to slaughter the Passover lamb, applying blood to the doorposts with hyssop, and explaining the meaning of the sacrifice to future generations.)",fulfillment1:"1 Corinthians 5:7",fulfillment1Text:"Get rid of the old yeast, that you may be a new unleavened batch, as you really are. For Christ, our Passover lamb, has been sacrificed.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Exodus 12:46",description:"Not a bone of the Lamb to be broken",otText:"It must be eaten inside one house. Do not take any of the meat outside the house, and do not break any of its bones.",fulfillment1:"John 19:31–36",fulfillment1Text:"31 It was the day of Preparation, and the next day was a high Sabbath. In order that the bodies would not remain on the cross during the Sabbath, the Jews asked Pilate to have the legs broken and the bodies removed. 32 So the soldiers came and broke the legs of the first man who had been crucified with Jesus, and then those of the other. 33 But when they came to Jesus and saw that He was already dead, they did not break His legs. 34 Instead, one of the soldiers pierced His side with a spear, and immediately blood and water flowed out. 35 He who saw this has testified to it, and his testimony is true. He knows that he is telling the truth, so that you also may believe. 36 For these things happened so that the Scripture would be fulfilled: “Not one of His bones will be broken.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Exodus 15:2",description:"His exaltation predicted as Yeshua",otText:"The LORD is my strength and my song, and He has become my salvation. He is my God, and I will praise Him, my father’s God, and I will exalt Him.",fulfillment1:"Acts 7:55–56",fulfillment1Text:"55 But Stephen, full of the Holy Spirit, looked intently into heaven and saw the glory of God, and Jesus standing at the right hand of God. 56 “Look,” he said, “I see heaven open and the Son of Man standing at the right hand of God.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Exodus 15:11",description:"His Character-Holiness",otText:"Who among the gods is like You, O LORD? Who is like You—majestic in holiness, awesome in glory, working wonders?",fulfillment1:"Luke 1:35",fulfillment1Text:"The angel replied, “The Holy Spirit will come upon you, and the power of the Most High will overshadow you. So the Holy One to be born will be called the Son of God.”",fulfillment2:"Acts 4:27",fulfillment2Text:"In fact, Herod and Pontius Pilate assembled together in this city with the Gentiles and the people of Israel against Your holy servant Jesus, whom You anointed."},{prophecy:"Exodus 17:6",description:"The Spiritual Rock of Israel",otText:"I will stand there before you by the rock at Horeb. Strike the rock, and water will come out of it for the people to drink.” So Moses did this in the sight of the elders of Israel.",fulfillment1:"1 Corinthians 10:4",fulfillment1Text:"and drank the same spiritual drink; for they drank from the spiritual rock that accompanied them, and that rock was Christ.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Exodus 33:19",description:"His Character-Merciful",otText:"And the LORD said, “I will cause all My goodness to pass in front of you, and I will proclaim My name, the LORD, in your presence. I will have mercy on whom I will have mercy, and I will have compassion on whom I will have compassion.”",fulfillment1:"Luke 1:72",fulfillment1Text:"to show mercy to our fathers and to remember His holy covenant,",fulfillment2:"",fulfillment2Text:""},{prophecy:"Leviticus 1:2–9",description:"His sacrifice a sweet smelling savor unto God",otText:"(Instructions for a burnt offering from the herd: it must be a male without blemish, presented at the entrance to the Tent of Meeting, where its blood is sprinkled and the offering is burned as a pleasing aroma.)",fulfillment1:"Ephesians 5:2",fulfillment1Text:"and walk in love, just as Christ loved us and gave Himself up for us as a fragrant offering and sacrifice to God.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Leviticus 14:11",description:"The leper cleansed-Sign to priesthood",otText:"The priest who cleanses him must present the person to be purified, along with his offerings, before the LORD at the entrance to the Tent of Meeting.",fulfillment1:"Luke 5:12–14",fulfillment1Text:"12 While Jesus was in one of the towns, a man came along who was covered with leprosy. When he saw Jesus, he fell with his face to the ground and begged Him, “Lord, if You are willing, You can make me clean.” 13 Jesus reached out His hand and touched the man. “I am willing,” He said. “Be clean!” And immediately the leprosy left him. 14 Then Jesus ordered him, “Do not tell anyone, but go, show yourself to the priest and offer the sacrifices that Moses commanded for your cleansing, as a testimony to them.”",fulfillment2:"Acts 6:7",fulfillment2Text:"So the word of God continued to spread. The number of disciples in Jerusalem grew rapidly, and a large number of priests became obedient to the faith."},{prophecy:"Leviticus 16:15–17",description:"Prefigures Christ’s once-for-all death",otText:"(Instructions for the Day of Atonement: slaughtering the goat for the sin offering, bringing its blood behind the veil, and making atonement for the Most Holy Place and the Tent of Meeting.)",fulfillment1:"Hebrews 9:7–14",fulfillment1Text:"7 But only the high priest entered the second room, and then only once a year, and never without blood, which he offered for himself and for the sins the people had committed in ignorance. 8 The Holy Spirit was showing by this that the way into the Most Holy Place had not yet been disclosed as long as the first tabernacle was still standing. 9 This is an illustration for the present time, because the gifts and sacrifices being offered were unable to clear the conscience of the worshiper. 10 They are only a matter of food and drink and various ceremonial washings—external regulations imposed until the time of reformation. 11 But when Christ came as High Priest of the good things that are now here, He went through the greater and more perfect tabernacle that is not made by hands and is not a part of this creation. 12 He did not enter by means of the blood of goats and calves; but He entered the Most Holy Place once for all by His own blood, having obtained eternal redemption. 13 For if the blood of goats and bulls and the ashes of a heifer sprinkled on those who are ceremonially unclean sanctify them so that their bodies are clean, 14 how much more will the blood of Christ, who through the eternal Spirit offered Himself unblemished to God, purify our consciences from works of death, so that we may serve the living God!",fulfillment2:"",fulfillment2Text:""},{prophecy:"Leviticus 16:27",description:"Suffering outside the Camp",otText:"The bull and the goat for the sin offerings, whose blood was brought into the Most Holy Place to make atonement, must be taken outside the camp; their hides, flesh, and dung must be burned up.",fulfillment1:"Matthew 27:33",fulfillment1Text:"They came to a place called Golgotha (which means “The Place of the Skull”).",fulfillment2:"Hebrews 13:11–12",fulfillment2Text:"11 The high priest carries the blood of animals into the Most Holy Place as a sin offering, but the bodies are burned outside the camp. 12 And so Jesus also suffered outside the city gate to sanctify the people by His own blood."},{prophecy:"Leviticus 17:11",description:"The Blood-the life of the flesh",otText:"For the life of a creature is in the blood, and I have given it to you to make atonement for yourselves on the altar; it is the blood that makes atonement for one’s life.",fulfillment1:"Matthew 26:28",fulfillment1Text:"This is My blood of the covenant, which is poured out for many for the forgiveness of sins.",fulfillment2:"Mark 10:45",fulfillment2Text:"For even the Son of Man did not come to be served, but to serve, and to give His life as a ransom for many.”"},{prophecy:"Leviticus 17:11",description:"It is the blood that makes atonement",otText:"For the life of a creature is in the blood, and I have given it to you to make atonement for yourselves on the altar; it is the blood that makes atonement for one’s life.",fulfillment1:"Romans 3:23–24",fulfillment1Text:"23 for all have sinned and fall short of the glory of God, 24 and are justified freely by His grace through the redemption that is in Christ Jesus.",fulfillment2:"1 John 1:7",fulfillment2Text:"But if we walk in the light as He is in the light, we have fellowship with one another, and the blood of Jesus His Son cleanses us from all sin."},{prophecy:"Leviticus 23:36–37",description:"The Drink-offering: “If any man thirst”",otText:"36 For seven days present food offerings to the LORD. On the eighth day hold a sacred assembly... 37 These are the LORD’s appointed feasts, which you are to proclaim as sacred assemblies for presenting food offerings to the LORD—burnt offerings and grain offerings, sacrifices and drink offerings...",fulfillment1:"John 7:37",fulfillment1Text:"On the last and greatest day of the feast, Jesus stood up and called out in a loud voice, “If anyone is thirsty, let him come to Me and drink.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Numbers 9:12",description:"Not a bone of Him broken",otText:"They must not leave any of it until morning or break any of its bones. They must follow all the regulations for the Passover.",fulfillment1:"John 19:31–36",fulfillment1Text:"31 It was the day of Preparation, and the next day was a high Sabbath. In order that the bodies would not remain on the cross during the Sabbath, the Jews asked Pilate to have the legs broken and the bodies removed. 32 So the soldiers came and broke the legs of the first man who had been crucified with Jesus, and then those of the other. 33 But when they came to Jesus and saw that He was already dead, they did not break His legs. 34 Instead, one of the soldiers pierced His side with a spear, and immediately blood and water flowed out. 35 He who saw this has testified to it, and his testimony is true. He knows that he is telling the truth, so that you also may believe. 36 For these things happened so that the Scripture would be fulfilled: “Not one of His bones will be broken.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Numbers 21:9",description:"The serpent on a pole-Christ lifted up",otText:"So Moses made a bronze snake and put it up on a pole. Then when anyone was bitten by a snake and looked at the bronze snake, they lived.",fulfillment1:"John 3:14–18",fulfillment1Text:"14 Just as Moses lifted up the snake in the wilderness, so the Son of Man must be lifted up, 15 that everyone who believes in Him may have eternal life. 16 For God so loved the world that He gave His one and only Son, that whoever believes in Him shall not perish but have eternal life. 17 For God did not send His Son into the world to condemn the world, but to save the world through Him. 18 Whoever believes in Him is not condemned, but whoever does not believe has already been condemned, because he has not believed in the name of God’s one and only Son.",fulfillment2:"John 12:32",fulfillment2Text:"And I, when I am lifted up from the earth, will draw all men to Myself.”"},{prophecy:"Numbers 24:17",description:"Time: “I shall see him, but not now.”",otText:"I see him, but not now; I behold him, but not near. A star will come out of Jacob; a scepter will rise out of Israel. He will crush the foreheads of Moab and the skulls of all the people of Sheth.",fulfillment1:"John 1:14",fulfillment1Text:"The Word became flesh and made His dwelling among us. We have seen His glory, the glory of the one and only Son from the Father, full of grace and truth.",fulfillment2:"Galatians 4:4",fulfillment2Text:"But when the time had fully come, God sent His Son, born of a woman, born under the law,"},{prophecy:"Deuteronomy 18:15",description:"“This is of a truth that prophet”",otText:"The LORD your God will raise up for you a prophet like me from among your own brothers. You must listen to him.",fulfillment1:"John 6:14",fulfillment1Text:"When the people saw the sign that Jesus had performed, they began to say, “Truly this is the Prophet who is to come into the world.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Deuteronomy 18:15–16",description:"“Had you believed Moses, you would believe me.”",otText:"15 The LORD your God will raise up for you a prophet like me... 16 This is what you asked of the LORD your God at Horeb on the day of the assembly when you said, “Let us not hear the voice of the LORD our God or see this great fire anymore, or we will die.”",fulfillment1:"John 5:45–47",fulfillment1Text:"45 Do not think that I will accuse you before the Father. Your accuser is Moses, in whom you have put your hope. 46 If you believed Moses, you would believe Me, for he wrote about Me. 47 But since you do not believe what he wrote, how will you believe what I say?”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Deuteronomy 18:18",description:"Sent by the Father to speak His word",otText:"I will raise up for them a prophet like you from among their brothers. I will put My words in his mouth, and he will tell them everything I command him.",fulfillment1:"John 8:28–29",fulfillment1Text:"28 So Jesus said, “When you have lifted up the Son of Man, then you will know that I am He, and that I do nothing on My own, but speak exactly what the Father has taught Me. 29 He who sent Me is with Me. He has not left Me alone, because I always do what pleases Him.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Deuteronomy 18:19",description:"Whoever will not hear must bear his sin",otText:"And I will hold to account anyone who does not listen to My words that the prophet speaks in My name.",fulfillment1:"Acts 3:22–23",fulfillment1Text:"22 For Moses said, ‘The Lord your God will raise up for you a prophet like me from among your brothers. You must listen to Him in everything He tells you. 23 Everyone who does not listen to Him will be completely cut off from among his people.’",fulfillment2:"",fulfillment2Text:""},{prophecy:"Deuteronomy 21:23",description:"Cursed is he that hangs on a tree",otText:"you must not leave the body on the tree overnight, but you must be sure to bury him that day, because anyone who is hung on a tree is under God’s curse.",fulfillment1:"Galatians 3:10–13",fulfillment1Text:"10 All who rely on works of the law are under a curse. For it is written: “Cursed is everyone who does not continue to do everything written in the Book of the Law.” 11 Now it is clear that no one is justified before God by the law, because, “The righteous will live by faith.” 12 The law, however, is not based on faith; on the contrary, “The person who does these things will live by them.” 13 Christ redeemed us from the curse of the law by becoming a curse for us. For it is written: “Cursed is everyone who is hung on a tree.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Joshua 5:14–15",description:"The Captain of our salvation",otText:"14 “Neither,” he replied. “I have now come as commander of the LORD’s army.” Then Joshua fell facedown... 15 The commander of the LORD’s army replied, “Take off your sandals, for the place where you are standing is holy.”",fulfillment1:"Hebrews 2:10",fulfillment1Text:"In bringing many sons to glory, it was fitting for God, for whom and through whom all things exist, to make the author of their salvation perfect through suffering.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Ruth 4:4–10",description:"Christ, our kinsman, has redeemed us",otText:"(Boaz acts as the kinsman-redeemer, agreeing to buy the land from Naomi and take Ruth as his wife to maintain the family name, legally securing the lineage that leads to David and the Messiah.)",fulfillment1:"Ephesians 1:3–7",fulfillment1Text:"3 Blessed be the God and Father of our Lord Jesus Christ, who has blessed us in Christ with every spiritual blessing in the heavenly realms. 4 For He chose us in Him before the foundation of the world to be holy and blameless in His presence. In love 5 He predestined us for adoption as His sons through Jesus Christ, according to the good pleasure of His will, 6 to the praise of His glorious grace, which He has freely given us in the Beloved One. 7 In Him we have redemption through His blood, the forgiveness of our trespasses, according to the riches of His grace,",fulfillment2:"",fulfillment2Text:""},{prophecy:"1 Samuel 2:35",description:"A Faithful Priest",otText:"Then I will raise up for Myself a faithful priest, who will do what is in My heart and mind. I will build him a lasting house, and he will walk before My anointed one for all time.",fulfillment1:"Hebrews 2:17",fulfillment1Text:"For this reason He had to be made like His brothers in every way, so that He might become a merciful and faithful high priest in service to God, to make atonement for the sins of the people.",fulfillment2:"Hebrews 3:1–3",fulfillment2Text:"1 Therefore, holy brothers, who share in the heavenly calling, set your focus on Jesus, the apostle and high priest whom we confess. 2 He was faithful to the One who appointed Him, just as Moses was faithful in all God’s house. 3 For Jesus has been counted worthy of greater glory than Moses, just as the builder of a house has greater honor than the house itself."},{prophecy:"1 Samuel 2:10",description:"Shall be an anointed King to the Lord",otText:"Those who oppose the LORD will be shattered. He will thunder from heaven against them; the LORD will judge the ends of the earth. He will give strength to His king and exalt the horn of His anointed.”",fulfillment1:"Matthew 28:18",fulfillment1Text:"Then Jesus came to them and said, “All authority in heaven and on earth has been given to Me.",fulfillment2:"John 12:15",fulfillment2Text:"“Do not be afraid, O daughter of Zion; behold, your King is coming, seated on a donkey’s colt.”"},{prophecy:"2 Samuel 7:12",description:"David’s Seed",otText:"When your days are over and you rest with your fathers, I will raise up your offspring after you, who will come from your own body, and I will establish his kingdom.",fulfillment1:"Matthew 1:1",fulfillment1Text:"This is the record of the genealogy of Jesus Christ, the son of David, the son of Abraham:",fulfillment2:"",fulfillment2Text:""},{prophecy:"2 Samuel 7:13",description:"His Kingdom is everlasting",otText:"He is the one who will build a house for My Name, and I will establish the throne of his kingdom forever.",fulfillment1:"2 Peter 1:11",fulfillment1Text:"and you will receive a lavish reception into the eternal kingdom of our Lord and Savior Jesus Christ.",fulfillment2:"",fulfillment2Text:""},{prophecy:"2 Samuel 7:14a",description:"The Son of God",otText:"I will be his Father, and he will be My son.",fulfillment1:"Luke 1:32",fulfillment1Text:"He will be great and will be called the Son of the Most High. The Lord God will give Him the throne of His father David,",fulfillment2:"Romans 1:3–4",fulfillment2Text:"3 regarding His Son, who was a descendant of David according to the flesh, 4 and who through the Spirit of holiness was declared with power to be the Son of God by His resurrection from the dead: Jesus Christ our Lord."},{prophecy:"2 Samuel 7:16",description:"David’s house established forever",otText:"Your house and your kingdom will endure before Me forever; your throne will be established forever.’”",fulfillment1:"Luke 3:31",fulfillment1Text:"the son of Melea, the son of Menna, the son of Mattatha, the son of Nathan, the son of David,",fulfillment2:"Revelation 22:16",fulfillment2Text:"“I, Jesus, have sent My angel to give you this testimony for the churches. I am the Root and the Offspring of David, the bright Morning Star.”"},{prophecy:"2 Kings 2:11",description:"The bodily ascension to heaven illustrated",otText:"As they were walking along and talking together, suddenly a chariot of fire with horses of fire appeared and separated the two of them, and Elijah went up into heaven in a whirlwind.",fulfillment1:"Luke 24:51",fulfillment1Text:"While He was blessing them, He left them and was carried up into heaven.",fulfillment2:"",fulfillment2Text:""},{prophecy:"1 Chronicles 17:11",description:"David’s Seed",otText:"When your days are over... I will raise up your offspring... and I will establish his kingdom.",fulfillment1:"Matthew 1:1",fulfillment1Text:"This is the record of the genealogy of Jesus Christ, the son of David, the son of Abraham:",fulfillment2:"Matthew 9:27",fulfillment2Text:"As Jesus moved on from there, two blind men followed Him, shouting, “Have mercy on us, Son of David!”"},{prophecy:"1 Chronicles 17:12–13",description:"To reign on David’s throne forever",otText:"12 He is the one who will build a house for Me, and I will establish his throne forever. 13 I will be his Father, and he will be My son.",fulfillment1:"Luke 1:32–33",fulfillment1Text:"32 He will be great and will be called the Son of the Most High. The Lord God will give Him the throne of His father David, 33 and He will reign over the house of Jacob forever. His kingdom will never end!”",fulfillment2:"",fulfillment2Text:""},{prophecy:"1 Chronicles 17:13",description:"“I will be His Father, He…my Son.”",otText:"I will be his Father, and he will be My son. I will never take My loving devotion away from him, as I took it from the one who was before you.",fulfillment1:"Hebrews 1:5",fulfillment1Text:"For to which of the angels did God ever say: “You are My Son; today I have become Your Father”? Or again: “I will be His Father, and He will be My Son”?",fulfillment2:"",fulfillment2Text:""},{prophecy:"Job 9:32–33",description:"Mediator between man and God",otText:"32 For God is not a man like me, that I could answer Him... 33 There is no mediator between us, to lay his hand upon us both.",fulfillment1:"1 Timothy 2:5",fulfillment1Text:"For there is one God and one mediator between God and men, the man Christ Jesus,",fulfillment2:"",fulfillment2Text:""},{prophecy:"Job 19:23–27",description:"The Resurrection predicted",otText:"23 Oh, that my words were recorded... 25 I know that my Redeemer lives, and that in the end He will stand upon the earth. 26 And after my skin has been destroyed, yet in my flesh I will see God.",fulfillment1:"John 5:24–29",fulfillment1Text:"24 Truly, truly, I tell you, whoever hears My word and believes Him who sent Me has eternal life and will not come under judgment. Indeed, he has crossed over from death to life. 25 Truly, truly, I tell you, the hour is coming and has now come when the dead will hear the voice of the Son of God, and those who hear will live. 26 For as the Father has life in Himself, so He has granted the Son to have life in Himself. 27 And He has given Him authority to execute judgment, because He is the Son of Man. 28 Do not be amazed at this, for the hour is coming when all who are in their graves will hear His voice 29 and come out—those who have done good to the resurrection of life, and those who have done evil to the resurrection of judgment.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 2:1–3",description:"The enmity of kings foreordained",otText:"1 Why do the nations rage and the peoples plot in vain? 2 The kings of the earth take their stand and the rulers gather together against the LORD and against His Anointed One...",fulfillment1:"Acts 4:25–28",fulfillment1Text:"25 You spoke by the Holy Spirit through the mouth of Your servant, our father David: ‘Why do the nations rage and the peoples plot in vain? 26 The kings of the earth take their stand and the rulers gather together against the Lord and against His Anointed One.’ 27 In fact, Herod and Pontius Pilate assembled together in this city with the Gentiles and the people of Israel against Your holy servant Jesus, whom You anointed. 28 They did what Your hand and Your will had foreordained to happen.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 2:2",description:"To own the title, Anointed (Christ)",otText:"The kings of the earth take their stand and the rulers gather together against the LORD and against His Anointed One:",fulfillment1:"John 1:41",fulfillment1Text:"He first found his brother Simon and told him, “We have found the Messiah” (which is translated as Christ).",fulfillment2:"Acts 2:36",fulfillment2Text:"Therefore let all Israel know with certainty: God has made this Jesus, whom you crucified, both Lord and Christ!”"},{prophecy:"Psalm 2:6",description:"His Character-Holiness",otText:"“I have installed My King on Zion, upon My holy mountain.”",fulfillment1:"John 8:46",fulfillment1Text:"Which of you can prove Me guilty of sin? If I speak the truth, why do you not believe Me?",fulfillment2:"Revelation 3:7",fulfillment2Text:"“To the angel of the church in Philadelphia write: These are the words of the Holy One, the True One, who holds the key of David. What He opens no one can shut, and what He shuts no one can open."},{prophecy:"Psalm 2:6",description:"To own the title King",otText:"“I have installed My King on Zion, upon My holy mountain.”",fulfillment1:"Matthew 2:2",fulfillment1Text:"and asked, “Where is the One who has been born King of the Jews? We saw His star in the east and have come to worship Him.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 2:7",description:"Declared the Beloved Son",otText:"I will proclaim the decree of the LORD: He said to Me, “You are My Son; today I have become Your Father.",fulfillment1:"Matthew 3:17",fulfillment1Text:"And a voice from heaven said, “This is My beloved Son, in whom I am well pleased!”",fulfillment2:"Romans 1:4",fulfillment2Text:"and who through the Spirit of holiness was declared with power to be the Son of God by His resurrection from the dead: Jesus Christ our Lord."},{prophecy:"Psalm 2:7–8",description:"The Crucifixion and Resurrection intimated",otText:"7 ...“You are My Son; today I have become Your Father. 8 Ask Me, and I will make the nations Your inheritance, the ends of the earth Your possession.",fulfillment1:"Acts 13:29–33",fulfillment1Text:"29 When they had carried out all that was written about Him, they took Him down from the tree and laid Him in a tomb. 30 But God raised Him from the dead, 31 and for many days He appeared to those who had come up with Him from Galilee to Jerusalem—the very ones who are now His witnesses to the people. 32 And we tell you the good news: What God promised our fathers 33 He has fulfilled for us, their children, by raising up Jesus. As it is written in the second Psalm: “You are My Son; today I have become Your Father.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 2:8–9",description:"Rule the nations with a rod of iron",otText:"8 Ask Me, and I will make the nations Your inheritance... 9 You will break them with an iron scepter; You will shatter them like pottery.”",fulfillment1:"Revelation 2:27",fulfillment1Text:"‘He will rule them with an iron scepter; He will shatter them like pottery’—just as I have received authority from My Father.",fulfillment2:"Revelation 12:5",fulfillment2Text:"And she gave birth to a son, a male child, who will rule all the nations with an iron scepter. And her child was caught up to God and to His throne."},{prophecy:"Psalm 2:12",description:"Life comes through faith in Him",otText:"Kiss the Son, lest He be angry and you perish in your rebellion, for His wrath can flare up in a moment. Blessed are all who take refuge in Him.",fulfillment1:"John 20:31",fulfillment1Text:"But these are written so that you may believe that Jesus is the Christ, the Son of God, and that by believing you may have life in His name.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 8:2",description:"The mouths of babes perfect His praise",otText:"From the mouths of children and infants You have ordained praise because of Your adversaries, to silence the enemy and the avenger.",fulfillment1:"Matthew 21:16",fulfillment1Text:"“Do You hear what these children are saying?” they asked. “Yes,” Jesus replied. “Have you never read: ‘From the mouths of children and infants You have ordained praise’?”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 8:5–6",description:"His humiliation and exaltation",otText:"5 You made him a little lower than the angels; You crowned him with glory and honor. 6 You made him ruler of the works of Your hands; You placed everything under his feet:",fulfillment1:"Hebrews 2:5–9",fulfillment1Text:"5 For it is not to angels that He has subjected the world to come, about which we are speaking. 6 But there is a place where someone has testified: “What is man that You are mindful of him, or the son of man that You care for him? 7 You made him a little lower than the angels; You crowned him with glory and honor 8 and placed everything under his feet.” In subjecting all things to him, God left nothing outside of his control. Yet at present we do not see everything subject to him. 9 But we see Jesus, who was made a little lower than the angels, now crowned with glory and honor because He suffered death, so that by the grace of God He might taste death for everyone.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 9:7–10",description:"Judge the world in righteousness",otText:"7 The LORD reigns forever; He has established His throne for judgment. 8 He will judge the world in righteousness... 10 Those who know Your name will trust in You...",fulfillment1:"Acts 17:31",fulfillment1Text:"For He has set a day when He will judge the world with justice by the Man He has appointed. He has given proof of this to all men by raising Him from the dead.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 16:10",description:"Was not to see corruption",otText:"For You will not abandon my soul to Sheol, nor will You let Your Holy One see decay.",fulfillment1:"Acts 2:31",fulfillment1Text:"Foreseeing this, he spoke of the resurrection of the Christ, that He was not abandoned to Hades, nor did His body see decay.",fulfillment2:"Acts 13:35",fulfillment2Text:"So it is also stated elsewhere: ‘You will not let Your Holy One see decay.’"},{prophecy:"Psalm 16:9–11",description:"Was to arise from the dead",otText:"9 Therefore my heart is glad... 10 For You will not abandon my soul to Sheol... 11 You have made known to me the path of life; You will fill me with joy in Your presence...",fulfillment1:"John 20:9",fulfillment1Text:"(For they did not yet understand from the Scripture that Jesus had to rise from the dead.)",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 17:15",description:"The resurrection predicted",otText:"As for me, I will behold Your face in righteousness; when I awake, I will be satisfied with Your presence.",fulfillment1:"Luke 24:6",fulfillment1Text:"He is not here; He has risen! Remember how He told you while He was still with you in Galilee:",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 18:2–3",description:"The horn of salvation",otText:"2 The LORD is my rock, my fortress, and my deliverer... 3 I will call upon the LORD, who is worthy to be praised; so shall I be saved from my enemies.",fulfillment1:"Luke 1:69–71",fulfillment1Text:"69 He has raised up a horn of salvation for us in the house of His servant David, 70 as He spoke through His holy prophets from of old, 71 salvation from our enemies and from the hand of all who hate us,",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 22:1",description:"Forsaken because of sins of others",otText:"My God, my God, why have You forsaken me? Why are You so far from saving me, so far from my words of groaning?",fulfillment1:"2 Corinthians 5:21",fulfillment1Text:"God made Him who knew no sin to be sin for us, so that in Him we might become the righteousness of God.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 22:1",description:"“My God, my God, why have You forsaken me?”",otText:"(Duplicate entry of the above verse.)",fulfillment1:"Matthew 27:46",fulfillment1Text:"About the ninth hour Jesus cried out in a loud voice, “Eli, Eli, lema sabachthani?” which means, “My God, My God, why have You forsaken Me?”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 22:2",description:"Darkness upon Calvary for three hours",otText:"O my God, I cry out by day, but You do not answer, by night, and I find no rest.",fulfillment1:"Matthew 27:45",fulfillment1Text:"From the sixth hour until the ninth hour darkness came over all the land.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 22:7",description:"They shoot out the lip and shake the head",otText:"All who see me mock me; they sneer and shake their heads:",fulfillment1:"Matthew 27:39–44",fulfillment1Text:"39 Those who passed by hurled insults at Him, wagging their heads 40 and saying, “You who are going to destroy the temple and rebuild it in three days, save Yourself! If You are the Son of God, come down from the cross.” 41 In the same way the chief priests, scribes, and elders mocked Him, saying, 42 “He saved others, but He cannot save Himself. He is the King of Israel! Let Him come down now from the cross, and we will believe in Him. 43 He trusts in God. Let God deliver Him now if He wants Him. For He said, ‘I am the Son of God.’” 44 In the same way the robbers who were crucified with Him also insulted Him.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 22:8",description:"“He trusted in God, let Him deliver Him”",otText:"“He trusts in the LORD, let the LORD deliver him; let the LORD rescue him, since He delights in him.”",fulfillment1:"Matthew 27:43",fulfillment1Text:"He trusts in God. Let God deliver Him now if He wants Him. For He said, ‘I am the Son of God.’",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 22:9–10",description:"Born the Savior",otText:"9 Yet You brought me forth from the womb... 10 From birth I was cast upon You; from my mother’s womb You have been my God.",fulfillment1:"Luke 2:7",fulfillment1Text:"and she gave birth to her firstborn, a son. She wrapped Him in swaddling clothes and laid Him in a manger, because there was no room for them in the inn.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 22:12–13",description:"They seek His death",otText:"12 Many bulls surround me; strong bulls of Bashan encircle me. 13 They open their mouths against me like lions, roaring and mangling their prey.",fulfillment1:"John 19:6",fulfillment1Text:"As soon as the chief priests and officers saw Him, they shouted, “Crucify! Crucify!” But Pilate told them, “You take Him and crucify Him, for I find no basis for a charge against Him.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 22:14",description:"His blood poured out when they pierced His side",otText:"I am poured out like water, and all my bones are out of joint. My heart has turned to wax; it has melted within me.",fulfillment1:"John 19:34",fulfillment1Text:"Instead, one of the soldiers pierced His side with a spear, and immediately blood and water flowed out.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 22:14–15",description:"Suffered agony on Calvary",otText:"14 ...all my bones are out of joint... 15 My strength is dried up like a potsherd, and my tongue sticks to the roof of my mouth; You lay me in the dust of death.",fulfillment1:"Mark 15:34–37",fulfillment1Text:"34 And at the ninth hour Jesus cried out in a loud voice, “Eloi, Eloi, lema sabachthani?” which means, “My God, My God, why have You forsaken Me?” 35 When some of those standing nearby heard this, they said, “Look, He is calling Elijah.” 36 Someone ran and filled a sponge with sour wine, put it on a reed, and offered it to Jesus to drink, saying, “Leave Him alone. Let us see if Elijah comes to take Him down.” 37 Then Jesus let out a loud cry and breathed His last.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 22:15",description:"He thirsted",otText:"My strength is dried up like a potsherd, and my tongue sticks to the roof of my mouth; You lay me in the dust of death.",fulfillment1:"John 19:28",fulfillment1Text:"After this, knowing that everything had now been finished, and so that the Scripture would be fulfilled, Jesus said, “I am thirsty.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 22:16",description:"They pierced His hands and His feet",otText:"For dogs surround me; a pack of evil men encircles me; they have pierced my hands and my feet.",fulfillment1:"John 19:34–37",fulfillment1Text:"34 Instead, one of the soldiers pierced His side with a spear, and immediately blood and water flowed out. 35 He who saw this has testified to it, and his testimony is true. He knows that he is telling the truth, so that you also may believe. 36 For these things happened so that the Scripture would be fulfilled: “Not one of His bones will be broken.” 37 And as another Scripture says: “They will look on the One they have pierced.”",fulfillment2:"John 20:27",fulfillment2Text:"Then He said to Thomas, “Put your finger here and see My hands. Reach out your hand and put it into My side. Stop doubting and believe.”"},{prophecy:"Psalm 22:17–18",description:"Stripped Him before the stares of men",otText:"17 I can count all my bones; people stare and gloat over me. 18 They divide my garments among them and cast lots for my clothing.",fulfillment1:"Luke 23:34–35",fulfillment1Text:"34 Jesus said, “Father, forgive them, for they do not know what they are doing.” And they divided up His clothes by casting lots. 35 The people stood watching, and the rulers even sneered at Him, saying, “He saved others; let Him save Himself if He is the Christ of God, the Chosen One.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 22:18",description:"They parted His garments",otText:"They divide my garments among them and cast lots for my clothing.",fulfillment1:"John 19:23–24",fulfillment1Text:"23 When the soldiers had crucified Jesus, they took His garments and divided them into four parts, one for each soldier, and they also took His tunic. Now the tunic was seamless, woven in one piece from top to bottom. 24 So they said to one another, “Let us not tear it, but cast lots to see whose it will be.” This happened so that the Scripture would be fulfilled: “They divided My garments among them, and for My clothing they cast lots.” So the soldiers did these things.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 22:20–21",description:"He committed Himself to God",otText:"20 Deliver my soul from the sword, my very life from the power of the dog. 21 Save me from the mouth of the lion; at the horns of the wild oxen, You have answered me.",fulfillment1:"Luke 23:46",fulfillment1Text:"Then Jesus called out in a loud voice, “Father, into Your hands I commit My spirit.” And when He had said this, He breathed His last.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 22:20–21",description:"Satanic power bruising the Redeemer’s heel",otText:"(Duplicate entry of the above verses.)",fulfillment1:"Hebrews 2:14",fulfillment1Text:"Therefore, since the children have flesh and blood, He too shared in their humanity, so that by His death He might destroy him who holds the power of death, that is, the devil,",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 22:22",description:"His Resurrection declared",otText:"I will proclaim Your name to my brothers; I will praise You in the assembly.",fulfillment1:"John 20:17",fulfillment1Text:"“Do not cling to Me,” Jesus said, “for I have not yet ascended to the Father. But go and tell My brothers, ‘I am ascending to My Father and your Father, to My God and your God.’”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 22:27–28",description:"He shall be the governor of the nations",otText:"27 All the ends of the earth will remember and turn to the LORD... 28 For kingship belongs to the LORD, and He rules over the nations.",fulfillment1:"Colossians 1:16",fulfillment1Text:"For in Him all things were created, things in heaven and on earth, visible and invisible, whether thrones or dominions or rulers or authorities. All things were created through Him and for Him.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 22:31",description:"“It is finished”",otText:"They will come and proclaim His righteousness to a people yet unborn—for He has done it.",fulfillment1:"John 19:30",fulfillment1Text:"When Jesus had received the sour wine, He said, “It is finished.” And bowing His head, He yielded up His spirit.",fulfillment2:"Hebrews 10:10–12",fulfillment2Text:"10 And by this will, we have been sanctified through the offering of the body of Jesus Christ once for all. 11 Day after day every priest stands and ministers, offering again and again the same sacrifices, which can never take away sins. 12 But when this Priest had offered for all time one sacrifice for sins, He sat down at the right hand of God."},{prophecy:"Psalm 23:1",description:"“I am the Good Shepherd”",otText:"The LORD is my shepherd; I shall not want.",fulfillment1:"John 10:11",fulfillment1Text:"I am the good shepherd. The good shepherd lays down His life for the sheep.",fulfillment2:"1 Peter 2:25",fulfillment2Text:"For you were like sheep going astray, but now you have returned to the Shepherd and Overseer of your souls."},{prophecy:"Psalm 24:3",description:"His exaltation predicted",otText:"Who may ascend the hill of the LORD? Who may stand in His holy place?",fulfillment1:"Acts 1:11",fulfillment1Text:"“Men of Galilee,” they said, “why do you stand here looking into the sky? This same Jesus, who has been taken from you into heaven, will come back in the same way you have seen Him go into heaven.”",fulfillment2:"Philippians 2:9",fulfillment2Text:"Therefore God exalted Him to the highest place and gave Him the name above every name,"},{prophecy:"Psalm 23:1",description:"His resurrection predicted",otText:"(Repeated as Psalm 30:3 in order? Psa 30:3 text follows:) O LORD, You brought my soul up from Sheol; You spared me from among those going down to the Pit.",fulfillment1:"Acts 2:32",fulfillment1Text:"God has raised this Jesus to life, to which we are all witnesses.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 31:5",description:"“Into Your hands I commit my spirit”",otText:"Into Your hands I commit my spirit; You have redeemed me, O LORD, God of truth.",fulfillment1:"Luke 23:46",fulfillment1Text:"Then Jesus called out in a loud voice, “Father, into Your hands I commit My spirit.” And when He had said this, He breathed His last.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 31:11",description:"His acquaintances fled from Him",otText:"Because of all my adversaries, I am a reproach to my neighbors and an object of dread to my friends...",fulfillment1:"Mark 14:50",fulfillment1Text:"Then all His disciples deserted Him and fled.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 31:13",description:"They took counsel to put Him to death",otText:"For I hear the whispering of many; terror is on every side. They conspire against me; they plot to take my life.",fulfillment1:"Matthew 27:1",fulfillment1Text:"When morning came, all the chief priests and elders of the people conspired against Jesus to put Him to death.",fulfillment2:"John 11:53",fulfillment2Text:"So from that day on they conspired to put Him to death."},{prophecy:"Psalm 31:14–15",description:"“He trusted in God, let Him deliver him”",otText:"14 But I trust in You, O LORD; I say, “You are my God.” 15 My times are in Your hands; deliver me from the hands of my enemies and from those who pursue me.",fulfillment1:"Matthew 27:43",fulfillment1Text:"He trusts in God. Let God deliver Him now if He wants Him. For He said, ‘I am the Son of God.’",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 34:20",description:"Not a bone of Him broken",otText:"He protects all his bones; not one of them will be broken.",fulfillment1:"John 19:31–36",fulfillment1Text:"31 It was the day of Preparation, and the next day was a high Sabbath. In order that the bodies would not remain on the cross during the Sabbath, the Jews asked Pilate to have the legs broken and the bodies removed. 32 So the soldiers came and broke the legs of the first man who had been crucified with Jesus, and then those of the other. 33 But when they came to Jesus and saw that He was already dead, they did not break His legs. 34 Instead, one of the soldiers pierced His side with a spear, and immediately blood and water flowed out. 35 He who saw this has testified to it, and his testimony is true. He knows that he is telling the truth, so that you also may believe. 36 For these things happened so that the Scripture would be fulfilled: “Not one of His bones will be broken.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 35:11",description:"False witnesses rose up against Him",otText:"Malicious witnesses step forward; they question me about things I do not know.",fulfillment1:"Matthew 26:59",fulfillment1Text:"Now the chief priests and the whole Sanhedrin were looking for false testimony against Jesus so that they could put Him to death.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 35:19",description:"He was hated without a cause",otText:"Let not my gloating enemies rejoice over me; let not those who hate me without cause wink their eyes.",fulfillment1:"John 15:25",fulfillment1Text:"But this is to fulfill what is written in their Law: ‘They hated Me without a cause.’",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 38:11",description:"His friends stood afar off",otText:"My friends and companions avoid my plague; my kinsmen stand far off.",fulfillment1:"Luke 23:49",fulfillment1Text:"But all those who knew Him, including the women who had followed Him from Galilee, stood at a distance watching these things.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 38:12",description:"Enemies try to entangle Him by craft",otText:"Those who seek my life lay their snares; those who wish me harm speak of ruin and plot deception all day long.",fulfillment1:"Mark 14:1",fulfillment1Text:"It was now two days before the Passover and the Feast of Unleavened Bread. And the chief priests and scribes were looking for a way to arrest Jesus by stealth and kill Him.",fulfillment2:"Matthew 22:15",fulfillment2Text:"Then the Pharisees went out and plotted how to trap Him in His words."},{prophecy:"Psalm 38:12–13",description:"Silent before His accusers",otText:"12 ...those who wish me harm speak of ruin... 13 But I am like a deaf man who does not hear, like a mute man who does not open his mouth.",fulfillment1:"Matthew 27:12–14",fulfillment1Text:"12 When He was accused by the chief priests and elders, He gave no answer. 13 Then Pilate asked Him, “Do You not hear how many things they are testifying against You?” 14 But Jesus gave him no answer, not even to a single charge, so that the governor was greatly amazed.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 38:20",description:"He went about doing good",otText:"Those who repay my good with evil attack me for pursuing what is good.",fulfillment1:"Acts 10:38",fulfillment1Text:"how God anointed Jesus of Nazareth with the Holy Spirit and with power, and how He went about doing good and healing all who were under the power of the devil, because God was with Him.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 40:2–5",description:"The joy of His resurrection predicted",otText:"2 He brought me up from the pit of destruction... 5 Many, O LORD my God, are the wonders You have done...",fulfillment1:"John 20:20",fulfillment1Text:"After He had said this, He showed them His hands and His side. The disciples rejoiced when they saw the Lord.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 40:6–8",description:"His delight-the will of the Father",otText:"6 Sacrifice and offering You did not desire... 7 Then I said, “Here I am! I have come! It is written of me in the scroll: 8 I delight to do Your will, O my God; Your law is within my heart.”",fulfillment1:"John 4:34",fulfillment1Text:"“My food,” said Jesus, “is to do the will of Him who sent Me and to finish His work.",fulfillment2:"Hebrews 10:5–10",fulfillment2Text:"5 Therefore, when Christ came into the world, He said: “Sacrifice and offering You did not desire, but a body You prepared for Me. 6 In burnt offerings and sin offerings You took no pleasure. 7 Then I said, ‘Here I am, it is written about Me in the scroll: I have come to do Your will, O God.’” 8 First He said, “Sacrifices and offerings, burnt offerings and sin offerings You did not desire, nor did You take pleasure in them” (although they are required by the law). 9 Then He said, “Here I am, I have come to do Your will.” He sets aside the first to establish the second. 10 And by this will, we have been sanctified through the offering of the body of Jesus Christ once for all."},{prophecy:"Psalm 40:9",description:"He was to preach the Righteousness in Israel",otText:"I proclaim righteousness in the great assembly; see, I do not seal my lips, as You know, O LORD.",fulfillment1:"Matthew 4:17",fulfillment1Text:"From that time on Jesus began to preach, “Repent, for the kingdom of heaven is near.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 40:14",description:"Confronted by adversaries in the Garden",otText:"May those who seek my life be disgraced and confounded; may those who wish me harm be turned back in shame.",fulfillment1:"John 18:4–6",fulfillment1Text:"4 Jesus, knowing all that was coming upon Him, stepped forward and asked them, “Whom are you looking for?” 5 “Jesus of Nazareth,” they answered. Jesus said, “I am He.” (And Judas the traitor was standing there with them.) 6 When Jesus said, “I am He,” they drew back and fell to the ground.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 41:9",description:"Betrayed by a familiar friend",otText:"Even my close friend whom I trusted, he who shared my bread, has lifted up his heel against me.",fulfillment1:"John 13:18",fulfillment1Text:"I am not speaking about all of you; I know whom I have chosen. But this is to fulfill the Scripture: ‘He who shares My bread has lifted up his heel against Me.’",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 45:2",description:"Words of Grace come from His lips",otText:"You are the most handsome of men; grace has been poured upon Your lips, since God has blessed You forever.",fulfillment1:"John 1:17",fulfillment1Text:"For the law was given through Moses; grace and truth came through Jesus Christ.",fulfillment2:"Luke 4:22",fulfillment2Text:"All spoke well of Him and were amazed at the gracious words that came from His lips. “Isn’t this Joseph’s son?” they asked."},{prophecy:"Psalm 45:6",description:"To own the title, God or Elohim",otText:"Your throne, O God, will last forever and ever; a scepter of justice will be the scepter of Your kingdom.",fulfillment1:"Hebrews 1:8",fulfillment1Text:"But about the Son He says: “Your throne, O God, will last forever and ever, and righteousness will be the scepter of Your kingdom.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 45:7",description:"A special anointing by the Holy Spirit",otText:"You have loved righteousness and hated wickedness; therefore God, Your God, has anointed You with the oil of joy above Your companions.",fulfillment1:"Matthew 3:16",fulfillment1Text:"As soon as Jesus was baptized, He went up out of the water. At that moment heaven was opened, and He saw the Spirit of God descending like a dove and lighting on Him.",fulfillment2:"Hebrews 1:9",fulfillment2Text:"You have loved righteousness and hated wickedness; therefore God, Your God, has anointed You with the oil of joy above Your companions.”"},{prophecy:"Psalm 45:7–8",description:"Called the Christ (Messiah or Anointed)",otText:"7 ...anointed You with the oil of joy... 8 All Your garments are fragrant with myrrh and aloes and cassia...",fulfillment1:"Luke 2:11",fulfillment1Text:"Today in the city of David a Savior has been born to you. He is Christ the Lord!",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 45:17",description:"His name remembered forever",otText:"I will perpetuate your memory through all generations; therefore the nations will praise you forever and ever.",fulfillment1:"Ephesians 1:20–21",fulfillment1Text:"20 which He exerted in Christ when He raised Him from the dead and seated Him at His right hand in the heavenly realms, 21 far above all rule and authority, power and dominion, and every name that is named, not only in this age, but also in the one to come.",fulfillment2:"Hebrews 1:8",fulfillment2Text:"But about the Son He says: “Your throne, O God, will last forever and ever, and righteousness will be the scepter of Your kingdom."},{prophecy:"Psalm 55:12–14",description:"Betrayed by a friend, not an enemy",otText:"12 For it is not an enemy who insults me... 13 But it is you, a man like myself, my companion and my close friend...",fulfillment1:"John 13:18",fulfillment1Text:"I am not speaking about all of you; I know whom I have chosen. But this is to fulfill the Scripture: ‘He who shares My bread has lifted up his heel against Me.’",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 55:15",description:"Unrepentant death of the Betrayer",otText:"Let death come blindly upon them; let them go down alive to Sheol, for evil dwells in their midst.",fulfillment1:"Matthew 27:3–5",fulfillment1Text:"3 When Judas, who had betrayed Him, saw that Jesus was condemned, he was filled with remorse and returned the thirty pieces of silver to the chief priests and elders. 4 “I have sinned by betraying innocent blood,” he said. “What is that to us?” they replied. “That is your responsibility.” 5 So Judas threw the silver into the temple and left. Then he went away and hanged himself.",fulfillment2:"Acts 1:16–19",fulfillment2Text:"16 “Brothers, the Scripture had to be fulfilled which the Holy Spirit spoke long ago through the mouth of David concerning Judas, who served as a guide for those who arrested Jesus— 17 for he was one of our number and shared in this ministry.” 18 (With the reward for his wickedness, Judas bought a field; there he fell headlong, his body burst open and all his intestines spilled out. 19 Everyone in Jerusalem heard about this, so they called that field in their language Akeldama, that is, Field of Blood.)"},{prophecy:"Psalm 68:18",description:"To give gifts to men",otText:"You have ascended on high; You have led captives in Your train; You have received gifts from men...",fulfillment1:"Ephesians 4:7–16",fulfillment1Text:"(Summary: Christ gave gifts to people—apostles, prophets, evangelists, pastors, and teachers—to equip the saints for ministry and build up the body of Christ until all reach unity and maturity.)",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 68:18",description:"Ascended into Heaven",otText:"(Duplicate entry of the above verse.)",fulfillment1:"Luke 24:51",fulfillment1Text:"While He was blessing them, He left them and was carried up into heaven.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 69:4",description:"Hated without a cause",otText:"Those who hate me without a cause outnumber the hairs of my head; many are those who would destroy me—my enemies who lie. Though I did not steal, I must give back what I did not take.",fulfillment1:"John 15:25",fulfillment1Text:"But this is to fulfill what is written in their Law: ‘They hated Me without a cause.’",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 69:8",description:"A stranger to own brethren",otText:"I have become a stranger to my brothers, an alien to my mother’s sons.",fulfillment1:"John 1:11",fulfillment1Text:"He came to His own, and His own did not receive Him.",fulfillment2:"John 7:5",fulfillment2Text:"For even His own brothers did not believe in Him."},{prophecy:"Psalm 69:9",description:"Zealous for the Lord’s House",otText:"For zeal for Your house has consumed me, and the insults of those who insult You have fallen on me.",fulfillment1:"John 2:17",fulfillment1Text:"His disciples remembered that it is written: “Zeal for Your house will consume Me.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 69:14–20",description:"Messiah’s anguish of soul before crucifixion",otText:"14 Rescue me from the mire; do not let me sink. Deliver me from those who hate me... 19 You know my reproach, my shame, and my dishonor; all my adversaries are before You. 20 Scorn has broken my heart, and I am in despair; I looked for sympathy, but there was none, for comforters, but I found no one.",fulfillment1:"Matthew 26:36–45",fulfillment1Text:"(Details Jesus’ prayer and agony in Gethsemane, and the disciples falling asleep three times until the hour of His betrayal arrived.)",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 69:20",description:"“My soul is exceeding sorrowful”",otText:"Scorn has broken my heart, and I am in despair; I looked for sympathy, but there was none, for comforters, but I found no one.",fulfillment1:"Matthew 26:38",fulfillment1Text:"Then He said to them, “My soul is consumed with sorrow to the point of death. Stay here and keep watch with Me.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 69:21",description:"Given vinegar in thirst",otText:"They put gall into my food and gave me vinegar for my thirst.",fulfillment1:"Matthew 27:34",fulfillment1Text:"there they offered Him wine to drink, mixed with gall; but after tasting it, He refused to drink it.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 69:26",description:"The Savior given and smitten by God",otText:"For they persecute those You have struck and recount the pain of those You have wounded.",fulfillment1:"John 17:4",fulfillment1Text:"I have glorified You on earth by finishing the work You gave Me to do.",fulfillment2:"John 18:11",fulfillment2Text:"Jesus, however, commanded Peter, “Put your sword back in its sheath! Shall I not drink the cup the Father has given Me?”"},{prophecy:"Psalm 72:10–11",description:"Great persons were to visit Him",otText:"10 May the kings of Tarshish and the distant shores bring tribute; may the kings of Sheba and Seba offer gifts. 11 May all kings bow down to him and all nations serve him.",fulfillment1:"Matthew 2:1–11",fulfillment1Text:"(The account of the Magi following the star to Bethlehem, finding the child Jesus with Mary, bowing down to worship Him, and offering gifts of gold, frankincense, and myrrh.)",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 72:16",description:"The corn of wheat to fall into the Ground",otText:"May there be an abundance of grain in the land, flourishing on the mountaintops. May its fruit sway like Lebanon, and those from the city flourish like the grass of the field.",fulfillment1:"John 12:24–25",fulfillment1Text:"24 Truly, truly, I tell you, unless a grain of wheat falls into the ground and dies, it remains only a single seed. But if it dies, it produces many seeds. 25 Whoever loves his life will lose it, but whoever hates his life in this world will keep it for eternal life.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 72:17",description:"Belief on His name will produce offspring",otText:"May his name endure forever; may his name flourish as long as the sun. May all nations be blessed through him, and may they call him blessed.",fulfillment1:"John 1:12–13",fulfillment1Text:"12 But to all who did receive Him, to those who believed in His name, He gave the right to become children of God— 13 children born not of blood, nor of the desire or will of man, but born of God.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 72:17",description:"All nations shall be blessed by Him",otText:"(Duplicate) May his name endure forever...",fulfillment1:"Galatians 3:8",fulfillment1Text:"The Scripture foresaw that God would justify the Gentiles by faith, and foretold the gospel to Abraham: “All nations will be blessed through you.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 72:17",description:"All nations shall call Him blessed",otText:"(Duplicate) May his name endure forever...",fulfillment1:"John 12:13",fulfillment1Text:"They took palm branches and went out to meet Him, shouting: “Hosanna!” “Blessed is He who comes in the name of the Lord!” “Blessed is the King of Israel!”",fulfillment2:"Revelation 5:8–12",fulfillment2Text:"8 And when He had taken the scroll, the four living creatures and the twenty-four elders fell down before the Lamb. Each one had a harp and they were holding golden bowls full of incense, which are the prayers of the saints. 9 And they sang a new song: “Worthy are You to take the scroll and open its seals, because You were slain, and by Your blood You purchased for God those from every tribe and tongue and people and nation. 10 You have made them to be a kingdom and priests to serve our God, and they will reign upon the earth.” 11 Then I looked, and I heard the voices of many angels and living creatures and elders encircling the throne, numbering myriads upon myriads and thousands upon thousands. 12 In a loud voice they were saying: “Worthy is the Lamb who was slain, to receive power and riches and wisdom and strength and honor and glory and blessing!”"},{prophecy:"Psalm 78:1–2",description:"He would teach in parables",otText:"1 Give ear, O my people, to my teaching; incline your ears to the words of my mouth. 2 I will open my mouth in parables; I will utter riddles from of old,",fulfillment1:"Matthew 13:34–35",fulfillment1Text:"34 Jesus spoke all these things to the crowd in parables. He did not tell them anything without using a parable. 35 So was fulfilled what was spoken through the prophet: “I will open My mouth in parables; I will utter things hidden since the foundation of the world.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 78:2b",description:"To speak the Wisdom of God with authority",otText:"I will utter riddles from of old,",fulfillment1:"Matthew 7:29",fulfillment1Text:"because He taught as one who had authority, and not as their scribes.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 80:17",description:"The Man of God’s right hand",otText:"Let Your hand be upon the man at Your right hand, the son of man You have raised up for Yourself.",fulfillment1:"Mark 14:61–62",fulfillment1Text:"61 But Jesus remained silent and made no reply. Again the high priest questioned Him, “Are You the Christ, the Son of the Blessed One?” 62 “I am,” said Jesus, “and you will see the Son of Man sitting at the right hand of Power and coming with the clouds of heaven.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 88",description:"The Suffering and Reproach of Calvary",otText:"(Summary: A desperate prayer of one overwhelmed by suffering and near death, feeling abandoned by God and forgotten in the depths of the Pit.)",fulfillment1:"Matthew 27:26–50",fulfillment1Text:"(The narrative of Jesus' flogging, being mocked by soldiers, the crucifixion at Golgotha, the insults of bystanders, and Jesus yielding up His spirit.)",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 88:8",description:"They stood afar off and watched",otText:"You have removed my friends from me; You have made me repulsive to them. I am confined and cannot escape.",fulfillment1:"Luke 23:49",fulfillment1Text:"But all those who knew Him, including the women who had followed Him from Galilee, stood at a distance watching these things.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 89:27",description:"Firstborn",otText:"I will also appoint him my firstborn, the highest of the kings of the earth.",fulfillment1:"Colossians 1:15–18",fulfillment1Text:"15 He is the image of the invisible God, the firstborn over all creation. 16 For in Him all things were created... 18 And He is the head of the body, the church...",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 89:27",description:"Emmanuel to be higher than earthly kings",otText:"(Duplicate) I will also appoint him my firstborn...",fulfillment1:"Luke 1:32–33",fulfillment1Text:"32 He will be great and will be called the Son of the Most High. The Lord God will give Him the throne of His father David, 33 and He will reign over the house of Jacob forever. His kingdom will never end!”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 89:35–37",description:"David’s Seed, throne, kingdom endure forever",otText:"35 Once for all I have sworn by My holiness—I will not lie to David— 36 that his offspring will endure forever, and his throne will flourish like the sun before Me. 37 It will be established forever like the moon, the faithful witness in the sky.”",fulfillment1:"Luke 1:32–33",fulfillment1Text:"(Duplicate of the entry above)",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 89:36–37",description:"His character-Faithfulness",otText:"36 ...his offspring will endure forever... 37 It will be established forever like the moon, the faithful witness in the sky.”",fulfillment1:"Rev 1:5; 19:11",fulfillment1Text:"1:5 and from Jesus Christ, the faithful witness... 19:11 Then I saw heaven standing open... and its rider is called Faithful and True.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 90:2",description:"He is from everlasting (Micah 5:2)",otText:"Before the mountains were born or You brought forth the earth and the world, from everlasting to everlasting You are God.",fulfillment1:"John 1:1",fulfillment1Text:"In the beginning was the Word, and the Word was with God, and the Word was God.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 91:11–12",description:"Identified as Messianic, used to tempt Christ",otText:"11 For He will command His angels concerning you to guard you in all your ways. 12 They will lift you up in their hands, so that you will not strike your foot against a stone.",fulfillment1:"Luke 4:10–11",fulfillment1Text:"10 For it is written: ‘He will command His angels concerning you to guard you carefully; 11 and they will lift you up in their hands, so that you will not strike your foot against a stone.’”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 97:9",description:"His exaltation predicted",otText:"For You, O LORD, are Most High over all the earth; You are exalted far above all gods.",fulfillment1:"Acts 1:11",fulfillment1Text:"“Men of Galilee,” they said, “why do you stand here looking into the sky? This same Jesus, who has been taken from you into heaven, will come back in the same way you have seen Him go into heaven.”",fulfillment2:"Ephesians 1:20",fulfillment2Text:"which He exerted in Christ when He raised Him from the dead and seated Him at His right hand in the heavenly realms,"},{prophecy:"Psalm 100:5",description:"His character-Goodness",otText:"For the LORD is good, and His loving devotion endures forever; His faithfulness continues through all generations.",fulfillment1:"Matthew 19:16–17",fulfillment1Text:"16 Just then a man came up to Jesus and inquired, “Teacher, what good thing must I do to obtain eternal life?” 17 ... “There is only One who is good. If you want to enter life, keep the commandments.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 102:1–11",description:"The Suffering and Reproach of Calvary",otText:"(Summary: A prayer of an afflicted man who is faint and pours out his lament before the LORD, describing his days as smoke and his heart as withered grass.)",fulfillment1:"John 19:16–30",fulfillment1Text:'(The account of Jesus being handed over to be crucified, the inscription on the cross, the soldiers casting lots for His tunic, and Jesus saying "It is finished" before dying.)',fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 102:25–27",description:"Messiah is the Preexistent Son",otText:"25 In the beginning You laid the foundations of the earth, and the heavens are the work of Your hands. 26 They will perish, but You remain... 27 But You remain the same, and Your years will never end.",fulfillment1:"Hebrews 1:10–12",fulfillment1Text:"10 And: “In the beginning, O Lord, You laid the foundations of the earth... 11 They will perish, but You remain... 12 ...You remain the same, and Your years will never end.”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 109:25",description:"Ridiculed",otText:"I have become an object of scorn to my accusers; when they see me, they shake their heads.",fulfillment1:"Matthew 27:39",fulfillment1Text:"Those who passed by hurled insults at Him, wagging their heads",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 110:1",description:"Son of David",otText:"The LORD said to my Lord: “Sit at My right hand until I put Your enemies under Your feet.”",fulfillment1:"Matthew 22:42–43",fulfillment1Text:"42 “What do you think about the Christ? Whose son is He?” “The son of David,” they replied. 43 Jesus said to them, “How then does David in the Spirit call Him ‘Lord’?...",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 110:1",description:"To ascend to the right-hand of the Father",otText:"(Duplicate) The LORD said to my Lord...",fulfillment1:"Mark 16:19",fulfillment1Text:"After the Lord Jesus had spoken to them, He was taken up into heaven and sat at the right hand of God.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 110:1",description:"David’s son called Lord",otText:"(Duplicate) The LORD said to my Lord...",fulfillment1:"Matthew 22:44–45",fulfillment1Text:"44 ‘The Lord said to my Lord: “Sit at My right hand until I put Your enemies under Your feet.”’ 45 So if David calls Him ‘Lord,’ how can He be David’s son?”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 110:4",description:"A priest after Melchizedek’s order",otText:"The LORD has sworn and will not change His mind: “You are a priest forever in the order of Melchizedek.”",fulfillment1:"Hebrews 6:20",fulfillment1Text:"where Jesus, our forerunner, has entered on our behalf. He has become a high priest forever, in the order of Melchizedek.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 112:4",description:"His character-Compassionate, Gracious, et al",otText:"Light dawns in the darkness for the upright—for the gracious, compassionate, and righteous man.",fulfillment1:"Matthew 9:36",fulfillment1Text:"When He saw the crowds, He had compassion on them, because they were harassed and helpless, like sheep without a shepherd.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 118:17–18",description:"Messiah’s Resurrection assured",otText:"17 I will not die, but I will live and proclaim what the LORD has done. 18 The LORD has disciplined me severely, but He has not given me over to death.",fulfillment1:"Luke 24:5–7",fulfillment1Text:"5 ... “Why do you look for the living among the dead? 6 He is not here; He has risen! ... 7 ‘The Son of Man must be delivered into the hands of sinful men... and on the third day rise again.’”",fulfillment2:"1 Corinthians 15:20",fulfillment2Text:"But Christ has indeed been raised from the dead, the firstfruits of those who have fallen asleep."},{prophecy:"Psalm 118:22–23",description:"The rejected stone is Head of the corner",otText:"22 The stone the builders rejected has become the cornerstone. 23 This is from the LORD, and it is amazing in our eyes.",fulfillment1:"Matthew 21:42–43",fulfillment1Text:"42 Jesus said to them, “Have you never read in the Scriptures: ‘The stone the builders rejected has become the cornerstone...’ 43 Therefore I tell you that the kingdom of God will be taken away from you...”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 118:26a",description:"The Blessed One presented to Israel",otText:"Blessed is he who comes in the name of the LORD.",fulfillment1:"Matthew 21:9",fulfillment1Text:"The crowds that went ahead of Him and those that followed were shouting: “Hosanna to the Son of David!” “Blessed is He who comes in the name of the Lord!” “Hosanna in the highest!”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 118:26b",description:"To come while Temple standing",otText:"We bless you from the house of the LORD.",fulfillment1:"Matthew 21:12–15",fulfillment1Text:'(Jesus enters the temple courts, drives out the money changers, heals the blind and lame, and children shout "Hosanna to the Son of David," much to the indignation of the chief priests.)',fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 132:11",description:"The Seed of David (the fruit of His Body)",otText:"The LORD swore an oath to David, a promise He will not revoke: “One of your own descendants I will place upon your throne.",fulfillment1:"Luke 1:32",fulfillment1Text:"He will be great and will be called the Son of the Most High. The Lord God will give Him the throne of His father David,",fulfillment2:"Acts 2:30",fulfillment2Text:"But because he was a prophet and knew that God had promised him on oath to seat one of his descendants on his throne,"},{prophecy:"Psalm 129:3",description:"He was scourged",otText:"The plowers plowed over my back; they made their furrows long.",fulfillment1:"Matthew 27:26",fulfillment1Text:"Then Pilate released Barabbas to them. But he had Jesus flogged, and handed Him over to be crucified.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 138:1–6",description:"The supremacy of David’s Seed amazes kings",otText:"1 I will give You thanks with all my heart... 6 Though the LORD is on high, He attends to the lowly; but the proud He knows from afar.",fulfillment1:"Matthew 2:2–6",fulfillment1Text:"2 and asked, “Where is the One who has been born King of the Jews?... 6 ‘But you, Bethlehem... out of you will come a ruler who will shepherd My people Israel.’”",fulfillment2:"",fulfillment2Text:""},{prophecy:"Psalm 147:3–6",description:"The earthly ministry of Christ described",otText:"3 He heals the brokenhearted and binds up their wounds... 6 The LORD sustains the humble but casts the wicked to the ground.",fulfillment1:"Luke 4:18",fulfillment1Text:"“The Spirit of the Lord is on Me, because He has anointed Me to preach good news to the poor. He has sent Me to proclaim deliverance to the captives and recovery of sight to the blind, to release the oppressed,",fulfillment2:"",fulfillment2Text:""},{prophecy:"Proverbs 1:23",description:"He will send the Spirit of God",otText:"If you had repented at my rebuke, then surely I would have poured out my spirit on you; I would have made my words known to you.",fulfillment1:"John 16:7",fulfillment1Text:"But I tell you the truth, it is for your benefit that I am going away. Unless I go away, the Advocate will not come to you; but if I go, I will send Him to you.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Proverbs 8:23",description:"Foreordained from everlasting",otText:"From eternity I was appointed, from the beginning, before the world began.",fulfillment1:"Revelation 13:8",fulfillment1Text:"All inhabitants of the earth will worship the beast—all whose names have not been written in the Lamb’s book of life, the Lamb who was slain from the creation of the world.",fulfillment2:"1 Peter 1:19–20",fulfillment2Text:"19 but with the precious blood of Christ, a lamb without blemish or defect. 20 He was chosen before the creation of the world, but was revealed in these last times for your sake."},{prophecy:"Song of Sol. 5:16",description:"The altogether lovely One",otText:"His mouth is sweetness itself; he is altogether lovely. This is my beloved, and this is my friend, O daughters of Jerusalem.",fulfillment1:"John 1:17",fulfillment1Text:"For the law was given through Moses; grace and truth came through Jesus Christ.",fulfillment2:"",fulfillment2Text:""},{prophecy:"Isaiah 2:3",description:"He shall teach all nations",otText:"And many peoples will come and say: “Come, let us go up to the mountain of the LORD... He will teach us His ways, so that we may walk in His paths.” For the law will go forth from Zion, and the word of the LORD from Jerusalem.",fulfillment1:"John 4:25",fulfillment1Text:"The woman said, “I know that Messiah” (called Christ) “is coming. When He comes, He will explain everything to us.”",fulfillment2:"",fulfillment2Text:""}]};